import React from 'react'
import useData from '../useData'
import useSplitPaymentStore from '../useSplitPaymentStore'

export function PlanCard({ plan, onClick }) {
    if (plan) {
        const { planTitle, planDuration, planTag, id } = plan
        return (
            <div className='relative border-4 border-indigo-500 rounded-lg bg-blue-800 cursor-pointer' onClick={() => onClick(plan)}>
                <div className='p-2 text-4xl text-white'>{planTitle}</div>
                <div className='absolute top-0 right-0 p-2 text-sm text-blue-600 border-indigo-500 rounded-lg bg-white'>{planTag}</div>
                <div className='p-2 text-xl text-white'>{planDuration + ' ' + 'months'}</div>
            </div>
        )
    }
}
function Plans() {
    const { data, loading, error } = useData()
    const { setActivePlan, activePlan } = useSplitPaymentStore((s) => s)

    function handleClick(plan) {
        setActivePlan(plan)
    }

    if (data) {
        return (
            <div className='grid grid-cols-4 gap-4 p-4'>
                {data.map((plan) => {
                    return (<PlanCard key={plan.id} plan={plan} onClick={handleClick} />)
                })}
            </div>
        )
    }
}

export default Plans
